mapper.update:
update elderly
name = #{name}, gender = #{gender}, age = #{age}, phone = #{phone}, address = #{address}, dining_point_id = #{diningPointId}, grid_code = #{gridCode}, health_info = #{healthInfo}, special_needs = #{specialNeeds}, id_card = #{idCard}, image = #{image}, update_time = #{updateTime},
where id = #{id}

mapper.select:
select e.id, e.user_id, e.name, e.gender, e.age, e.phone, e.address, e.dining_point_id, dp.name as diningPointName, e.grid_code, e.health_info, e.special_needs, e.id_card, e.image, e.create_time, e.update_time from elderly e left join dining_point dp on e.dining_point_id = dp.id
and e.name like concat('%',#{name},'%')
and e.user_id = #{userId}
and e.grid_code = #{gridCode}
order by e.create_time desc

select * from elderly


        and name like concat('%',#{name},'%')


        and user_id = #{userId}


        and grid_code = #{gridCode}


order by create_time desc
